3: export function getPanelPluginToMigrateTo(panel: any): string | undefined {
4:   // Graph needs special logic as it can be migrated to multiple panels
5:   // Also, graphite was previously migrated to graph in the schema version 2 migration in DashboardMigrator.ts
6:   // but this was a bug because in there graphite was set to graph, but since those migrations run
7:   // after PanelModel.restoreModel where autoMigrateFrom is set, this caused the graph migration to be skipped.
8:   // And this resulted in a dashboard with invalid panels.
9:   if (panel.type === 'graph' || panel.type === 'graphite') {
10:     if (panel.xaxis?.mode === 'series') {
11:       if (panel.legend?.values) {
12:         return 'bargauge';
13:       }
14: 
15:       return 'barchart';
16:     }
17: 
18:     if (panel.xaxis?.mode === 'histogram') {
19:       return 'histogram';
20:     }
21: 
22:     return 'timeseries';
23:   }
24: 
25:   return autoMigrateAngular[panel.type];
26: }
