182: // getNextPanelId finds the next available panel ID
183: func getNextPanelId(panels []map[string]interface{}) int {
184: 	max := 0
185: 	for _, panel := range panels {
186: 		if panelID, ok := panel["id"].(float64); ok && panelID > 0 {
187: 			if int(panelID) > max {
188: 				max = int(panelID)
189: 			}
190: 		}
191: 	}
192: 	return max + 1
193: }
