289: 	}
290: 	if meta["canStar"] == nil {
291: 		meta["canStar"] = true
292: 	}
293: 	if meta["canEdit"] == nil {
294: 		meta["canEdit"] = true
295: 	}
296: 	if meta["canDelete"] == nil {
297: 		meta["canDelete"] = true
298: 	}
299: 
300: 	// Derived properties
301: 	meta["showSettings"] = meta["canEdit"]
302: 
303: 	editable, _ := dashboard["editable"].(bool)
304: 	if meta["canSave"] == true && !editable {
305: 		meta["canMakeEditable"] = true
306: 	} else {
307: 		meta["canMakeEditable"] = false
308: 	}
309: 
310: 	meta["hasUnsavedFolderChange"] = false
