331: 
332: 	for _, item := range list {
333: 		if variable, ok := item.(map[string]interface{}); ok {
334: 			if current, ok := variable["current"].(map[string]interface{}); ok {
335: 				if value, exists := current["value"]; exists {
336: 					// Check for null value
337: 					if value == nil {
338: 						delete(current, "value")
339: 					} else if valueArray, isArray := value.([]interface{}); isArray {
340: 						// Check for null values in arrays
341: 						hasNull := false
342: 						for _, v := range valueArray {
343: 							if v == nil {
344: 								hasNull = true
345: 								break
346: 							}
347: 						}
348: 						if hasNull {
349: 							delete(current, "value")
350: 						}
351: 					}
352: 				}
353: 			}
354: 		}
355: 	}
356: }
