1009: // removeNullValuesRecursively removes null values from nested objects and arrays
1010: // This matches the frontend's JSON.stringify/parse behavior
1011: func removeNullValuesRecursively(data interface{}) {
1012: 	removeNullValuesRecursivelyWithContext(data, "")
1013: }
