1048: // cleanupDashboardDefaults removes dashboard-level default values that frontend filters out
1049: func cleanupDashboardDefaults(dashboard map[string]interface{}) {
1050: 	// Remove style if it's the default "dark" value
1051: 	removeIfDefaultValue(dashboard, "style", "dark")
1052: 
1053: 	// Remove hideControls if it's the default false value
