1062: 	// Remove transient properties that frontend filters out during getSaveModelClone()
1063: 	// These properties are lost during frontend's property copying loop in getSaveModelCloneOld()
1064: 	delete(dashboard, "iteration") // Template variable iteration timestamp
1065: 	delete(dashboard, "nav")       // Removed after V7 migration
1066: 	delete(dashboard, "pulldowns") // Removed after V6 migration - frontend doesn't have this property
1067: }
